INSERT INTO `hris_par_configs` (`par_config_key`,`par_config_value`,`par_config_created_by`,`par_config_created_on`,`par_config_updated_by`,`par_config_updated_on`) VALUES ('EMAIL_TEMPLETE_360_NOTIFICATION','<div style=\"text-align: left;\">\n    <p class=\"cDottedline\" style=\"font-family: \'Roboto\', Helvetica,sans-serif;padding-bottom: 5px;font-size: 17px;\n        line-height: 28px;padding-top: 40px;padding-left: 0;padding-right: 0;padding-right: 0;\n        color: #465868;text-align: left;border-top: 2px dotted #c3c5c9;margin-top: 0;\">\n        Dear <!-- [RECIPIENT_NAME] -->,\n    </p>\n\n    <p>You have a 360 review request to evaluate your colleague <!-- [ADDITIONAL_DATA] -->.<br/>\n        Please ensure that you complete and share 360 reviews before the deadline.</p>\n\n    <p><b>Submission Deadline:</b> <!-- [DEADLINE] --></p>\n    <p><b>Remaining Days:</b> <!-- [REMAINING_DAYS] --></p>\n\n    <p>If you have any questions about the PAR process or need assistance in completing your review, please do not\n        hesitate to reach out to the People Operations Team (POT).</p>\n</div>','system','2024-06-26 22:22:43.661114','system','2024-06-26 23:11:25.747465');
INSERT INTO `hris_par_configs` (`par_config_key`,`par_config_value`,`par_config_created_by`,`par_config_created_on`,`par_config_updated_by`,`par_config_updated_on`) VALUES ('EMAIL_TEMPLETE_360_REMINDER','<div style=\"text-align: left;\">\n    <p class=\"cDottedline\" style=\"font-family: \'Roboto\', Helvetica,sans-serif;padding-bottom: 5px;font-size: 17px;\n        line-height: 28px;padding-top: 40px;padding-left: 0;padding-right: 0;padding-right: 0;\n        color: #465868;text-align: left;border-top: 2px dotted #c3c5c9;margin-top: 0;\">\n        Dear <!-- [RECIPIENT_NAME] -->,\n    </p>\n\n    <p>This is a gentle reminder that the deadline for submitting 360 reviews for your collegues is fast approaching.\n        Please ensure that you complete and share 360 reviews before the deadline.</p>\n\n    <p><b>Par Cycle:</b> <!-- [PAR_CYCLE_NAME] --></p>\n    <p><b>Submission Deadline:</b> <!-- [DEADLINE] --></p>\n    <p><b>Remaining Days:</b> <!-- [REMAINING_DAYS] --></p>\n\n    <p><b>Reviewees</b></p>\n    <p>\n        <!-- [ADDITIONAL_DATA] -->\n    </p>\n\n    <p>If you have any questions about the PAR process or need assistance in completing your review, please do not\n        hesitate to reach out to the People Operations Team (POT).</p>\n</div>','system','2024-06-23 14:03:50.055410','system','2024-06-25 11:20:59.586394');
INSERT INTO `hris_par_configs` (`par_config_key`,`par_config_value`,`par_config_created_by`,`par_config_created_on`,`par_config_updated_by`,`par_config_updated_on`) VALUES ('EMAIL_TEMPLETE_EMPLOYEE_REMINDER','<div style=\"text-align: left;\">\n    <p class=\"cDottedline\" style=\"font-family: \'Roboto\', Helvetica,sans-serif;padding-bottom: 5px;font-size: 17px;\n        line-height: 28px;padding-top: 40px;padding-left: 0;padding-right: 0;padding-right: 0;\n        color: #465868;text-align: left;border-top: 2px dotted #c3c5c9;margin-top: 0;\">\n        Dear <!-- [RECIPIENT_NAME] -->,\n    </p>\n\n    <p>This is a gentle reminder that the deadline for submitting your Performance Appraisal Review (PAR) is\n        fast approaching. Please ensure that your PAR is completed and shared before the deadline.</p>\n\n    <p><b>Par Cycle:</b> <!-- [PAR_CYCLE_NAME] --></p>\n    <p><b>Submission Deadline:</b> <!-- [DEADLINE] --></p>\n    <p><b>Remaining Days:</b> <!-- [REMAINING_DAYS] --></p>\n\n    <p>If you have any questions about the PAR process or need assistance in completing your review, please do not\n        hesitate to reach out to the People Operations Team (POT).</p>\n</div>','system','2024-06-23 13:36:49.733099','system','2024-06-23 13:36:49.733099');
INSERT INTO `hris_par_configs` (`par_config_key`,`par_config_value`,`par_config_created_by`,`par_config_created_on`,`par_config_updated_by`,`par_config_updated_on`) VALUES ('EMAIL_TEMPLETE_EMPLOYEE_SHARED_NOTIFICATION','<div style=\"text-align: left;\">\n    <p class=\"cDottedline\"\n        style=\"font-family: \'Roboto\', Helvetica,sans-serif;padding-bottom: 5px;font-size: 17px;         line-height: 28px;padding-top: 40px;padding-left: 0;padding-right: 0;padding-right: 0;         color: #465868;text-align: left;border-top: 2px dotted #c3c5c9;margin-top: 0;\">\n        Dear <!-- [RECIPIENT_NAME] -->, </p>\n    <p>This is to inform you that <!-- [EMPLOYEE_NAME] --> has shared the Performance Appraisal Review (PAR) with you.</p>\n    <p>You can access the PAR of <!-- [EMPLOYEE_NAME] --> from <a href=\"<!-- [EMPLOYEE_PAR_LINK] -->\">here</a>.</p>\n</div>','system','2024-06-23 15:59:30.238304','system','2024-06-25 15:11:49.437636');
INSERT INTO `hris_par_configs` (`par_config_key`,`par_config_value`,`par_config_created_by`,`par_config_created_on`,`par_config_updated_by`,`par_config_updated_on`) VALUES ('EMAIL_TEMPLETE_LEAD_OVERDUE_REMINDER','<div style=\"text-align: left;\">\n    <p class=\"cDottedline\" style=\"font-family: \'Roboto\', Helvetica,sans-serif;padding-bottom: 5px;font-size: 17px;\n        line-height: 28px;padding-top: 40px;padding-left: 0;padding-right: 0;padding-right: 0;\n        color: #465868;text-align: left;border-top: 2px dotted #c3c5c9;margin-top: 0;\">\n        Dear <!-- [RECIPIENT_NAME] -->,\n    </p>\n\n    <p>This is to inform you that the deadline for submitting Performance Appraisal Reviews (PAR) for your team/s\n        has passed. Please ensure that you complete and share PARs of your team as soon as possible.</p>\n\n    <p style=\"color:red;\"><b>Par Cycle:</b> <!-- [PAR_CYCLE_NAME] --></p>\n    <p style=\"color:red;\"><b>Submission Deadline:</b> <!-- [DEADLINE] --></p>\n    <p style=\"color:red;\"><b>Overdue Days:</b> <!-- [REMAINING_DAYS] --></p>\n\n    <p><b>Details</b></p>\n    <p>\n        <!-- [ADDITIONAL_DATA] -->\n    </p>\n\n    <p>If you have any questions about the PAR process or need assistance in completing your review, please do not\n        hesitate to reach out to the People Operations Team (POT).</p>\n</div>','system','2024-06-23 13:44:09.118540','system','2024-06-23 13:44:09.118540');
INSERT INTO `hris_par_configs` (`par_config_key`,`par_config_value`,`par_config_created_by`,`par_config_created_on`,`par_config_updated_by`,`par_config_updated_on`) VALUES ('EMAIL_TEMPLETE_LEAD_REMINDER','<div style=\"text-align: left;\">\n    <p class=\"cDottedline\" style=\"font-family: \'Roboto\', Helvetica,sans-serif;padding-bottom: 5px;font-size: 17px;\n        line-height: 28px;padding-top: 40px;padding-left: 0;padding-right: 0;padding-right: 0;\n        color: #465868;text-align: left;border-top: 2px dotted #c3c5c9;margin-top: 0;\">\n        Dear <!-- [RECIPIENT_NAME] -->,\n    </p>\n\n    <p>This is a gentle reminder that the deadline for submitting Performance Appraisal Reviews (PAR) for your\n        team/s is fast approaching. Please ensure that you complete and share PARs of your team before the deadline</p>\n\n    <p><b>Par Cycle:</b> <!-- [PAR_CYCLE_NAME] --></p>\n    <p><b>Submission Deadline:</b> <!-- [DEADLINE] --></p>\n    <p><b>Remaining Days:</b> <!-- [REMAINING_DAYS] --></p>\n\n    <p><b>Details</b></p>\n    <p>\n        <!-- [ADDITIONAL_DATA] -->\n    </p>\n\n    <p>If you have any questions about the PAR process or need assistance in completing your review, please do not\n        hesitate to reach out to the People Operations Team (POT).</p>\n</div>','system','2024-06-23 13:40:11.625541','system','2024-06-23 13:40:11.625541');
INSERT INTO `hris_par_configs` (`par_config_key`,`par_config_value`,`par_config_created_by`,`par_config_created_on`,`par_config_updated_by`,`par_config_updated_on`) VALUES ('EMAIL_TEMPLETE_LEAD_SHARED_NOTIFICATION','<div style=\"text-align: left;\">\n    <p class=\"cDottedline\" style=\"font-family: \'Roboto\', Helvetica,sans-serif;padding-bottom: 5px;font-size: 17px;\n        line-height: 28px;padding-top: 40px;padding-left: 0;padding-right: 0;padding-right: 0;\n        color: #465868;text-align: left;border-top: 2px dotted #c3c5c9;margin-top: 0;\">\n        Dear <!-- [RECIPIENT_NAME] -->,\n    </p>\n\n    <p>This is to inform you that your Performance Appraisal Review (PAR) has been completed and shared by your\n        team lead.</p>\n\n    <p><b>Par Cycle:</b> <!-- [PAR_CYCLE_NAME] --></p>\n\n    <p>Please take the time to go through the feedback and insights provided. This is an excellent opportunity to\n        reflect on your achievements, recognize areas for development, and set goals for the upcoming period.</p>\n\n    <p>If you have any questions or would like to discuss your review in more detail, please feel free to reach out\n        to your lead or the People Operations Team (POT).</p>\n\n    <p>Thank you for your hard work and dedication throughout the past year. We look forward to your continued\n        contributions and success.</p>\n</div>','system','2024-06-23 14:58:47.153056','system','2024-06-23 15:31:19.179550');
INSERT INTO `hris_par_configs` (`par_config_key`,`par_config_value`,`par_config_created_by`,`par_config_created_on`,`par_config_updated_by`,`par_config_updated_on`) VALUES ('EMAIL_TEMPLETE_PAR_INVITATION','<div>\n    <p class=\"cDottedline\"\n        style=\"padding-bottom: 5px;font-size: 17px;line-height: 28px;padding-left: 0;padding-right: 0;padding-right: 0;color: #465868;text-align: left;border-top: 2px solid #c3c5c9;margin-top: 0;\">\n\n    <div style=\"text-align: left; padding-left: 40px; padding-right: 40px; padding-top: 40px;\">\n\n        <table cellspacing=\"0\" cellpadding=\"0\" border=\"0\" width=\"100%\" style=\"max-width:100%\">\n            <tbody>\n                <tr>\n                    <td>\n                        <p style=\"font-size:16px;margin:0px;line-height:26px;padding-bottom:20px\">\n                            Hi <!-- [RECIPIENT_NAME] -->,\n                        </p>\n                        <p style=\"font-size:16px;margin:0px;line-height:26px;padding-bottom:20px\">\n                            It\'s time for the\n                            <!-- [PAR_CYCLE_NAME] -->. All details\n                            on the PARs, ratings and filling\n                            the PAR forms are\n                            updated&nbsp;<a\n                                href=\"https://docs.google.com/presentation/d/1Rnp1MnK82fI9HTQRTu1RwyxI35i1bGX8ZkfHWG6OsWA/edit?usp=sharing\"\n                                style=\"color:rgb(255,115,0);text-decoration-line:none\" target=\"_blank\"\n                                data-saferedirecturl=\"https://www.google.com/url?q=https://docs.google.com/presentation/d/1Rnp1MnK82fI9HTQRTu1RwyxI35i1bGX8ZkfHWG6OsWA/edit?usp%3Dsharing&amp;source=gmail&amp;ust=1718857899513000&amp;usg=AOvVaw21X2cDtPklr4gNs9wryd5m\">here</a>.\n                        </p>\n                        <p style=\"\n                      font-size:16px;margin:0px;line-height:26px;padding-bottom:10px\">\n                            Folks who are experiencing their\n                            first PAR and would like to join\n                            a PAR briefing session please\n                            fill in your details&nbsp;<a\n                                href=\"https://docs.google.com/spreadsheets/d/1u-_6nHckGwUxYds6wh57_JC6zcibLdIX5hgxS0DMHzQ/edit?usp=sharing\"\n                                style=\"color:rgb(255,115,0);text-decoration-line:none\" target=\"_blank\"\n                                data-saferedirecturl=\"https://www.google.com/url?q=https://docs.google.com/spreadsheets/d/1u-_6nHckGwUxYds6wh57_JC6zcibLdIX5hgxS0DMHzQ/edit?usp%3Dsharing&amp;source=gmail&amp;ust=1718857899513000&amp;usg=AOvVaw0nuNh6YC0_yJKu1FG0iIJZ\">here</a>.\n                        </p>\n                        <p style=\"\n                      font-size:16px;margin:0px;line-height:26px;padding-bottom:10px\">\n                            You can access your PAR from <a href=\"<!-- [PAR_APP_BASE_URL] -->/?tab=employee\"\n                                style=\"color:rgb(255,115,0);text-decoration-line:none\" target=\"_blank\">here</a>.\n                        </p>\n                    </td>\n                </tr>\n                <tr>\n                    <td>\n                        <div style=\"padding: 20px\">\n                            <p class=\"cDottedline\"\n                                style=\"padding-bottom: 5px;font-size: 17px; line-height: 28px;padding-top: 40px;padding-left: 0;padding-right: 0;padding-right: 0; color: #465868;text-align: left;border-top: 2px dotted #c3c5c9;margin-top: 0;\">\n                            <h3\n                                style=\"color:rgb(68,68,68);font-size:28px;line-height:38px;text-align:center;margin:0px\">\n                                Filling your PAR forms</h3>\n                            <hr style=\"border-style:solid;border-color:rgb(255,115,0);width:570px\">\n                            <p style=\"font-size:16px;margin:20px 0px 0px;line-height:26px;padding-bottom:20px\">\n                                Please select\n                                <strong><!-- [PAR_CYCLE_NAME] --></strong>\n                                form\n                                on\n                                People HR\n                            </p>\n                            <table width=\"100%\" cellspacing=\"0\" border=\"0\" cellpadding=\"0\">\n                                <tbody>\n                                    <tr>\n                                        <td width=\"28%\"\n                                            style=\"padding:10px 15px 10px 0px;border-bottom:1px solid rgb(255,115,0);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:20px;font-weight:700;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Question</p>\n                                        </td>\n                                        <td width=\"36%\"\n                                            style=\"padding:10px 15px;border-bottom:1px solid rgb(255,115,0);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:20px;font-weight:700;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Employee</p>\n                                        </td>\n                                        <td width=\"36%\"\n                                            style=\"padding:10px 0px 10px 15px;border-bottom:1px solid rgb(255,115,0);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:20px;font-weight:700;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Team Lead</p>\n                                        </td>\n                                    </tr>\n                                    <tr>\n                                        <td\n                                            style=\"padding:10px 15px 10px 0px;border-bottom:1px solid rgb(153,153,153);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Overall Rating</p>\n                                        </td>\n                                        <td\n                                            style=\"padding:10px 15px;border-bottom:1px solid rgb(153,153,153);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Please select N/A\n                                            </p>\n                                        </td>\n                                        <td\n                                            style=\"padding:10px 0px 10px 15px;border-bottom:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Overall PAR rating\n                                            </p>\n                                        </td>\n                                    </tr>\n                                    <tr>\n                                        <td\n                                            style=\"padding:10px 15px 10px 0px;border-bottom:1px solid rgb(153,153,153);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Job Execution, Team\n                                                Work,\n                                                Communication, and\n                                                Leadership\n                                            </p>\n                                        </td>\n                                        <td\n                                            style=\"padding:10px 15px;border-bottom:1px solid rgb(153,153,153);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Employee\'s feedback\n                                                on\n                                                their\n                                                performance\n                                                highlights/\n                                                accomplishments on\n                                                the\n                                                mentioned\n                                                areas</p>\n                                        </td>\n                                        <td\n                                            style=\"padding:10px 0px 10px 15px;border-bottom:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Feedback from your\n                                                team\n                                                lead\n                                            </p>\n                                        </td>\n                                    </tr>\n                                    <tr>\n                                        <td\n                                            style=\"padding:10px 15px 10px 0px;border-bottom:1px solid rgb(153,153,153);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                360 Confirmation</p>\n                                        </td>\n                                        <td\n                                            style=\"padding:10px 15px;border-bottom:1px solid rgb(153,153,153);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Please type N/A</p>\n                                        </td>\n                                        <td\n                                            style=\"padding:10px 0px 10px 15px;border-bottom:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Confirmation that\n                                                360s\n                                                were\n                                                conducted with peers\n                                                /team\n                                                members,\n                                                cross-functional\n                                                leads,\n                                                cross-functional\n                                                peers\n                                                and\n                                                people reporting to\n                                                the\n                                                individual(if\n                                                applicable) -\n                                                To\n                                                be filled by TL only\n                                            </p>\n                                        </td>\n                                    </tr>\n                                </tbody>\n                            </table>\n                        </div>\n                    </td>\n                </tr>\n                <tr>\n                    <td>\n                        <div style=\"padding: 20px\">\n                            <h3\n                                style=\"color:rgb(68,68,68);font-size:28px;line-height:38px;text-align:center;margin:0px\">\n                                The Timelines</h3>\n                            <hr style=\"border-style:solid;border-color:rgb(255,115,0);width:570px\">\n                            <table width=\"100%\" cellspacing=\"0\" border=\"0\" cellpadding=\"0\" style=\"margin:40px 0px 0px\">\n                                <tbody>\n                                    <tr>\n                                        <td\n                                            style=\"padding:10px 15px 10px 0px;border-bottom:1px solid rgb(255,115,0);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:20px;font-weight:700;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Task</p>\n                                        </td>\n                                        <td\n                                            style=\"padding:10px 0px 10px 15px;border-bottom:1px solid rgb(255,115,0);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:20px;font-weight:700;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Deadline</p>\n                                        </td>\n                                    </tr>\n                                    <tr>\n                                        <td\n                                            style=\"padding:10px 15px 10px 0px;border-bottom:1px solid rgb(153,153,153);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Evaluation Start\n                                                Date\n                                            </p>\n                                        </td>\n                                        <td width=\"40%\"\n                                            style=\"padding:10px 0px 10px 15px;border-bottom:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;font-weight:700;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                <!-- [PAR_EVALUATION_START_DATE] -->\n                                            </p>\n                                        </td>\n                                    </tr>\n                                    <tr>\n                                        <td\n                                            style=\"padding:10px 15px 10px 0px;border-bottom:1px solid rgb(153,153,153);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Employee PAR\n                                                Submission\n                                                Deadline</p>\n                                        </td>\n                                        <td width=\"40%\"\n                                            style=\"vertical-align:top;padding:10px 0px 10px 15px;border-bottom:1px solid rgb(153,153,153)\">\n                                            <p\n                                                style=\"font-size:16px;font-weight:700;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                <!-- [EMPLOYEE_DEADLINE] -->\n                                            </p>\n                                        </td>\n                                    </tr>\n                                    <tr>\n                                        <td\n                                            style=\"padding:10px 15px 10px 0px;border-bottom:1px solid rgb(153,153,153);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                360 Submission\n                                                Deadline\n                                            </p>\n                                        </td>\n                                        <td width=\"40%\"\n                                            style=\"padding:10px 0px 10px 15px;border-bottom:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;font-weight:700;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                <!-- [360_DEADLINE] -->\n                                            </p>\n                                        </td>\n                                    </tr>\n                                    <tr>\n                                        <td\n                                            style=\"padding:10px 15px 10px 0px;border-bottom:1px solid rgb(153,153,153);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Lead PAR Submission\n                                                Deadline\n                                            </p>\n                                        </td>\n                                        <td width=\"40%\"\n                                            style=\"padding:10px 0px 10px 15px;border-bottom:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;font-weight:700;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                <!-- [LEAD_DEADLINE] -->\n                                            </p>\n                                        </td>\n                                    </tr>\n                                    <tr>\n                                        <td\n                                            style=\"padding:10px 15px 10px 0px;border-bottom:1px solid rgb(153,153,153);border-right:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                Evaluation End Date\n                                            </p>\n                                        </td>\n                                        <td width=\"40%\"\n                                            style=\"padding:10px 0px 10px 15px;border-bottom:1px solid rgb(153,153,153);vertical-align:top\">\n                                            <p\n                                                style=\"font-size:16px;font-weight:700;vertical-align:top;margin:0px;line-height:26px;color:rgb(68,68,68)\">\n                                                <!-- [PAR_EVALUATION_END_DATE] -->\n                                            </p>\n                                        </td>\n                                    </tr>\n                                </tbody>\n                            </table>\n                        </div>\n                    </td>\n                </tr>\n                <tr>\n                    <td>\n                        <div style=\"padding: 20px\">\n                            <p class=\"cDottedline\" style=\"padding-bottom: 5px;font-size: 17px;\n                      line-height: 28px;padding-top: 20px;padding-left: 0;padding-right: 0;padding-right: 0;\n                      color: #465868;text-align: left;border-top: 2px dotted #c3c5c9;margin-top: 0;\">\n                            <p style=\"font-size:16px;margin:0px;line-height:26px;\">\n                                Please feel free to reach out to\n                                your\n                                Team Leads\n                                or People Operations team if any of\n                                you\n                                have any\n                                questions/clarifications.</p>\n                        </div>\n                    </td>\n                </tr>\n            </tbody>\n        </table>\n    </div>\n</div>\n','system','2024-06-19 14:41:11.832339','system','2024-06-19 18:37:25.343239');
INSERT INTO `hris_par_configs` (`par_config_key`,`par_config_value`,`par_config_created_by`,`par_config_created_on`,`par_config_updated_by`,`par_config_updated_on`) VALUES ('EMAIL_TEMPLETE_SPECIAL_RATING_REMINDER','<div style=\"text-align: left;\">\n    <p class=\"cDottedline\" style=\"font-family: \'Roboto\', Helvetica,sans-serif;padding-bottom: 5px;font-size: 17px;\n        line-height: 28px;padding-top: 40px;padding-left: 0;padding-right: 0;padding-right: 0;\n        color: #465868;text-align: left;border-top: 2px dotted #c3c5c9;margin-top: 0;\">\n        Dear <!-- [RECIPIENT_NAME] -->,\n    </p>\n\n    <p>This is a gentle reminder that the deadline for submitting Special Ratings for your team is fast approaching.\n        Please ensure that you assign Special Ratings before the deadline.</p>\n\n    <p><b>Par Cycle:</b> <!-- [PAR_CYCLE_NAME] --></p>\n    <p><b>Submission Deadline:</b> <!-- [DEADLINE] --></p>\n    <p><b>Remaining Days:</b> <!-- [REMAINING_DAYS] --></p>\n\n    <p>If you have any questions about the PAR process or need assistance in completing your review, please do not\n        hesitate to reach out to the People Operations Team (POT).</p>\n</div>','system','2024-06-23 14:52:23.801320','system','2024-06-23 14:52:23.801320');
